() => {
  // Check for the results sidebar
  const sidebar = document.querySelector('[role="feed"], [aria-label*="Results"], .section-result, .m6QErb');
  const resultCards = document.querySelectorAll('.Nv2PK, .THOPZb, .hfpxzc, [data-result-index]');
  const allDivs = document.querySelectorAll('div');
  let resultLike = [];
  allDivs.forEach(d => {
    if (d.getAttribute('role') === 'article' || d.getAttribute('aria-label')?.includes('stars') || d.querySelector('[aria-label*="stars"]')) {
      resultLike.push(d.getAttribute('aria-label') || d.className?.substring(0, 50));
    }
  });

  return {
    url: window.location.href,
    sidebarExists: !!sidebar,
    resultCards: resultCards.length,
    resultLike: resultLike.slice(0, 5),
    bodyClasses: document.body.className,
    feedElements: document.querySelectorAll('[role="feed"]').length,
    mainContent: document.querySelector('[role="main"]')?.getAttribute('aria-label')
  };
}

