arguments.function:
() => {
  // Get all result cards - looking for the common Google Maps result containers
  const cards = document.querySelectorAll('.Nv2PK');
  const results = [];
  cards.forEach((card, i) => {
    const nameEl = card.querySelector('.qBF1Pd, .fontHeadlineSmall, h3');
    const ratingEl = card.querySelector('.MW4etd, [aria-label*="stars"], .ZkP5Je');
    const text = card.textContent?.trim().substring(0, 200);
    results.push({
      index: i,
      name: nameEl?.textContent?.trim(),
      rating: ratingEl?.textContent?.trim() || ratingEl?.getAttribute('aria-label'),
      snippet: text
    });
  });
  return results.slice(0, 8);
}

