    results.push({
      index: i,
      name: nameEl?.textContent?.trim(),
      rating: ratingEl?.textContent?.trim() || rating,
      hasAdLabel: !!adLabel,
      innerHTML: card.innerHTML.substring(0, 500)
    });
  });
  return results.slice(0, 8);
}

